// Feed list — source of truth. Customise to your interests.
const FEEDS = [
  { url: 'https://news.sap.com/feed/', source_id: 'sap-news', category: 'sap-official' },
  { url: 'https://news.sap.com/tags/sap-successfactors/feed/', source_id: 'sap-news-sf', category: 'sap-official' },
  { url: 'https://community.sap.com/khhcw49343/rss/board?board.id=hcm-blog-sap', source_id: 'hcm-blog-sap', category: 'sf-board' },
  { url: 'https://community.sap.com/khhcw49343/rss/search?q=tags:SAP%20SuccessFactors%20Employee%20Central', source_id: 'sf-ec', category: 'sf-module' },
  { url: 'https://community.sap.com/khhcw49343/rss/search?q=tags:SAP%20Roadmap', source_id: 'sap-roadmap', category: 'compliance' }
];

const sd = $getWorkflowStaticData('global');
sd.fetch_accumulator = [];
sd.fetch_failures = [];

return FEEDS.map(f => ({ json: f }));

// Inside loop iteration: items are RSS entries from one feed.
// $('Loop-Feeds').first() refers to the current batch's input (the feed metadata).
const sd = $getWorkflowStaticData('global');
if (!sd.fetch_accumulator) sd.fetch_accumulator = [];
if (!sd.fetch_failures) sd.fetch_failures = [];

let feedMeta;
try {
  feedMeta = $('Loop-Feeds').first().json;
} catch {
  feedMeta = { source_id: 'unknown', category: 'unknown', url: '' };
}

let validCount = 0;
let errorCount = 0;

for (const item of items) {
  // Skip error-shaped items from continueOnFail (rssFeedRead failed)
  if (item.json.error || (!item.json.title && !item.json.link)) {
    errorCount++;
    continue;
  }
  sd.fetch_accumulator.push({
    ...item.json,
    _source: feedMeta.source_id,
    _category: feedMeta.category
  });
  validCount++;
}

if (errorCount > 0 && validCount === 0) {
  sd.fetch_failures.push({
    source_id: feedMeta.source_id,
    url: feedMeta.url,
    at: new Date().toISOString()
  });
}

// Always return at least one item so the loop continues smoothly
return [{ json: { source_id: feedMeta.source_id, fetched: validCount, errors: errorCount } }];

const sd = $getWorkflowStaticData('global');
const all = sd.fetch_accumulator || [];
const failures = sd.fetch_failures || [];

// Persist a small failure log per day (for visibility, not loop control)
if (!sd.stats) sd.stats = {};
const today = new Date().toISOString().slice(0, 10);
if (!sd.stats[today]) sd.stats[today] = {};
sd.stats[today].feed_failures = failures;

// Clear accumulator for next run
sd.fetch_accumulator = [];
sd.fetch_failures = [];

// Handle empty case downstream via sentinel
if (all.length === 0) {
  return [{ json: { __empty: true } }];
}

return all.map(i => ({ json: i }));

// Pass-through sentinel for downstream empty handling
if (items.length === 1 && items[0].json.__empty === true) {
  return items;
}

// rss-parser returns `link` as string for RSS, but as object {href} or array for Atom/hybrid feeds.
function extractLink(raw) {
  let link = raw.link ?? raw.url ?? raw.guid ?? raw.id;
  if (Array.isArray(link)) {
    const alt = link.find(l => l && (l.rel === 'alternate' || l.rel === undefined));
    link = alt || link[0];
  }
  if (link && typeof link === 'object') {
    link = link.href || link.url || link['$'] && link['$'].href || '';
  }
  return typeof link === 'string' ? link : '';
}

function extractText(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') return v._ || v['#'] || v.value || v._text || '';
  return String(v);
}

// Non-crypto string hash (cyrb53) — n8n sandbox blocks the crypto module.
function hashUrl(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0, ch; i < str.length; i++) {
    ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0');
}

function stripHtml(html) {
  if (!html) return '';
  return html.replace(/<script[\s\S]*?<\/script>/gi, ' ')
             .replace(/<style[\s\S]*?<\/style>/gi, ' ')
             .replace(/<[^>]+>/g, ' ')
             .replace(/&[a-z]+;/gi, ' ')
             .replace(/\s+/g, ' ')
             .trim()
             .slice(0, 500);
}

function safeText(s) {
  if (!s) return '';
  return s.replace(/[\u0000-\u001f]/g, ' ')
          .replace(/[\[\]()<>`]/g, ' ')
          .replace(/\bsystem\s*[:>]/gi, 'system_')
          .replace(/\binstruction[s]?\s*[:>]/gi, 'instruction_')
          .replace(/\s+/g, ' ')
          .trim();
}

function canonicalUrl(url) {
  if (!url || typeof url !== 'string') return '';
  url = url.trim();
  // n8n sandbox may block the URL global; use regex validation instead.
  if (!/^https?:\/\/[^\s<>"']+$/i.test(url)) return '';
  // Strip tracking parameters via regex
  const trackParams = ['utm_source','utm_medium','utm_campaign','utm_content','utm_term','gclid','fbclid','mc_cid','mc_eid'];
  for (const p of trackParams) {
    url = url.replace(new RegExp('([?&])' + p + '=[^&#]*', 'gi'), '$1');
  }
  // Clean up dangling separators
  url = url.replace(/[?&]+(?=#|$)/, '').replace(/\?&/, '?').replace(/&&+/g, '&');
  return url;
}

const now = new Date().toISOString();
const results = [];

let droppedNoUrl = 0;
let droppedNoTitle = 0;

for (const item of items) {
  const raw = item.json;
  const url = canonicalUrl(extractLink(raw));
  if (!url) { droppedNoUrl++; continue; }

  const title = safeText(stripHtml(extractText(raw.title)));
  const description = safeText(stripHtml(extractText(raw.content || raw['content:encoded'] || raw.description || raw.summary || raw.contentSnippet)));
  if (!title) { droppedNoTitle++; continue; }

  results.push({
    json: {
      id: hashUrl(url),
      source: raw._source || 'unknown',
      category: raw._category || 'unknown',
      source_type: 'rss',
      title,
      url,
      description,
      published_at: raw.pubDate || raw.isoDate || raw.updated || raw.published || now,
      ingested_at: now,
      keyword_score: 0,
      llm_score: null,
      cluster_id: null,
      cluster_label: null,
      reasoning: null
    }
  });
}

// Persist diagnostic counters so we can debug field issues without re-running
const sd = $getWorkflowStaticData('global');
if (!sd.stats) sd.stats = {};
const today = new Date().toISOString().slice(0, 10);
if (!sd.stats[today]) sd.stats[today] = {};
sd.stats[today].normalize_input = items.length;
sd.stats[today].normalize_output = results.length;
sd.stats[today].normalize_dropped_no_url = droppedNoUrl;
sd.stats[today].normalize_dropped_no_title = droppedNoTitle;

if (results.length === 0) {
  return [{ json: { __empty: true, debug_no_url: droppedNoUrl, debug_no_title: droppedNoTitle } }];
}
return results;

// Pass-through sentinel
if (items.length === 1 && items[0].json.__empty === true) {
  return items;
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.seen_hashes) staticData.seen_hashes = {};
if (!staticData.stats) staticData.stats = {};

const dedupDays = $('Configuration').first().json.DEDUP_DAYS || 7;
const cutoff = new Date(Date.now() - dedupDays * 24 * 60 * 60 * 1000).toISOString();
for (const [hash, ts] of Object.entries(staticData.seen_hashes)) {
  if (ts < cutoff) delete staticData.seen_hashes[hash];
}

const statsCutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
for (const day of Object.keys(staticData.stats)) {
  if (day < statsCutoff) delete staticData.stats[day];
}

const today = new Date().toISOString().slice(0, 10);
if (!staticData.stats[today]) {
  staticData.stats[today] = {
    items_ingested: 0, items_after_dedup: 0,
    items_after_prefilter: 0, items_output: 0,
    llm_input_tokens: 0, llm_output_tokens: 0,
    feed_failures: []
  };
}
staticData.stats[today].items_ingested = (staticData.stats[today].items_ingested || 0) + items.length;
staticData.last_run = new Date().toISOString();

const newItems = [];
for (const item of items) {
  const hash = item.json.id;
  if (!staticData.seen_hashes[hash]) {
    staticData.seen_hashes[hash] = item.json.ingested_at;
    newItems.push(item);
  }
}

staticData.stats[today].items_after_dedup = (staticData.stats[today].items_after_dedup || 0) + newItems.length;

if (newItems.length === 0) {
  return [{ json: { __empty: true } }];
}
return newItems;

// Pass-through sentinel
if (items.length === 1 && items[0].json.__empty === true) {
  return items;
}

const KEYWORD_WEIGHTS = {
  'latest people profile': 10,
  'people profile': 8,
  'identity authentication': 9,
  'identity provisioning': 8,
  'ias': 6,
  'ips': 5,
  'event center': 9,
  'intelligent services': 7,
  'employee central': 7,
  'ec payroll': 8,
  'odata': 6,
  'api deprecat': 9,
  'breaking change': 10,
  'deprecation': 7,
  'build card': 8,
  'successfactors': 5,
  'sap sf': 5,
  'recruiting': 4,
  'onboarding': 4,
  'performance management': 5,
  'compensation': 4,
  'learning management': 5,
  'calibration': 4,
  'goal management': 4,
  'succession': 4,
  'talent intelligence': 6,
  'people analytics': 5,
  'time tracking': 4,
  'integration suite': 4,
  'cloud integration': 4,
  'cpi': 4,
  'cap framework': 4,
  'business application studio': 4,
  'btp': 3,
  'build work zone': 5,
  'release': 3,
  'roadmap': 3,
  'joule': 4,
  'gdpr': 4,
  'dsgvo': 4,
  'pay transparency': 7,
  'whats new': 5,
  "what's new": 5,
  's/4hana finance': -6,
  'accounts payable': -5,
  'procurement': -5,
  'business one': -8,
  'bydesign': -8,
  'oracle hcm': -6,
  'workday': -6,
  'abap': -3,
  'sap ecc': -4,
  'marketing cloud': -6,
  'sales cloud': -6
};

const THRESHOLD = $('Configuration').first().json.PREFILTER_THRESHOLD ?? 4;
const MAX_ITEMS = 30;

const scored = items.map(item => {
  const text = (item.json.title + ' ' + item.json.description).toLowerCase();
  let score = 0;
  for (const [kw, weight] of Object.entries(KEYWORD_WEIGHTS)) {
    if (text.includes(kw)) score += weight;
  }
  item.json.keyword_score = score;
  return item;
});

const filtered = scored
  .filter(i => i.json.keyword_score >= THRESHOLD)
  .sort((a, b) => b.json.keyword_score - a.json.keyword_score)
  .slice(0, MAX_ITEMS);

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (staticData.stats && staticData.stats[today]) {
  staticData.stats[today].items_after_prefilter = (staticData.stats[today].items_after_prefilter || 0) + filtered.length;
}

if (filtered.length === 0) {
  return [{ json: { __empty: true } }];
}
return filtered;

const payload = items.map(i => ({
  id: i.json.id,
  title: i.json.title,
  description: i.json.description,
  source: i.json.source
}));

return [{ json: { items_json: JSON.stringify(payload), item_count: payload.length } }];

const response = items[0].json;
let clusters;

try {
  let content = response.message?.content ?? response.content ?? response.choices?.[0]?.message?.content;
  if (typeof content === 'string') content = JSON.parse(content);
  clusters = content?.clusters;
  if (!Array.isArray(clusters)) throw new Error('No clusters array');
} catch (e) {
  return $('Prefilter').all()
    .filter(i => !i.json.__empty)
    .sort((a, b) => b.json.keyword_score - a.json.keyword_score)
    .slice(0, 10)
    .map(item => ({
      json: { ...item.json, cluster_label: 'Unclustered', cluster_id: 'fallback',
              reasoning: 'LLM scoring failed – keyword fallback active' }
    }));
}

const usage = response.usage || response.tokenUsage || {};
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (staticData.stats && staticData.stats[today]) {
  staticData.stats[today].llm_input_tokens = (staticData.stats[today].llm_input_tokens || 0) + (usage.prompt_tokens || usage.promptTokens || 0);
  staticData.stats[today].llm_output_tokens = (staticData.stats[today].llm_output_tokens || 0) + (usage.completion_tokens || usage.completionTokens || 0);
}

const originalItems = {};
for (const item of $('Prefilter').all()) {
  if (item.json.__empty) continue;
  originalItems[item.json.id] = item.json;
}

const allScored = [];
for (const cluster of clusters) {
  for (const scored of (cluster.items || [])) {
    const orig = originalItems[scored.id];
    if (!orig) continue;
    allScored.push({
      json: {
        ...orig,
        llm_score: scored.score,
        cluster_label: cluster.label || 'General',
        cluster_id: cluster.id || 'c?',
        reasoning: scored.reasoning || ''
      }
    });
  }
}

const top = allScored
  .sort((a, b) => (b.json.llm_score ?? 0) - (a.json.llm_score ?? 0))
  .slice(0, 10);

if (staticData.stats && staticData.stats[today]) {
  staticData.stats[today].items_output = (staticData.stats[today].items_output || 0) + top.length;
}

return top;

function escapeHtml(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
                  .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function safeUrl(u) {
  if (!u || typeof u !== 'string') return '#';
  return /^https?:\/\/[^\s<>"']+$/i.test(u.trim()) ? u.trim() : '#';
}

// Hardcoded SAP event calendar. Update annually.
// Dates marked approx=true are flagged "(date approx.)" until verified.
const EVENTS = [
  { name: 'DSAG-Jahreskongress 2026', date: '2026-09-15', location: 'Hamburg', url: 'https://www.dsag.de/jahreskongress', approx: true },
  { name: 'SAP TechEd 2026', date: '2026-10-14', location: 'Berlin / Bangalore (hybrid)', url: 'https://www.sap.com/about/events/sap-teched.html', approx: true },
  { name: 'SAP SuccessConnect 2026', date: '2026-10-27', location: 'Las Vegas', url: 'https://www.sap.com/about/events/successconnect.html', approx: true },
  { name: 'SAPinsider EMEA 2026', date: '2026-11-18', location: 'Kopenhagen', url: 'https://sapinsider.org/events/', approx: true },
  { name: 'ASUG Tech Connect 2027', date: '2027-01-19', location: 'Orlando', url: 'https://www.asug.com/events', approx: true },
  { name: 'SAPinsider Las Vegas 2027', date: '2027-03-09', location: 'Las Vegas', url: 'https://sapinsider.org/events/', approx: true },
  { name: 'SAP Sapphire 2027', date: '2027-05-12', location: 'Orlando', url: 'https://www.sap.com/about/events/sapphire.html', approx: true }
];

const now = new Date();
const dateStr = now.toLocaleDateString('en-GB', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: 'numeric' });
const timeStr = now.toLocaleTimeString('en-GB', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });

const clusters = {};
for (const item of items) {
  const label = item.json.cluster_label || 'General';
  if (!clusters[label]) clusters[label] = [];
  clusters[label].push(item.json);
}

let html = `<h2>SAP News Radar &ndash; ${escapeHtml(dateStr)} ${escapeHtml(timeStr)}</h2>`;
html += `<p><i>${Object.keys(clusters).length} clusters &middot; ${items.length} items</i></p>`;

for (const [label, clusterItems] of Object.entries(clusters)) {
  html += `<h3>${escapeHtml(label)}</h3><ul>`;
  for (const it of clusterItems) {
    const score = it.llm_score ?? it.keyword_score ?? 0;
    html += `<li><b>[Score ${escapeHtml(score)}]</b> `
         + `<a href="${escapeHtml(safeUrl(it.url))}">${escapeHtml(it.title)}</a> `
         + `<i>(${escapeHtml(it.source)})</i><br/>`
         + `<i>${escapeHtml(it.reasoning || (it.description ? it.description.slice(0, 200) : ''))}</i></li>`;
  }
  html += '</ul>';
}

// Events-Block – immer am Ende, nächste 8 Monate
const eightMonthsLater = new Date(now);
eightMonthsLater.setMonth(eightMonthsLater.getMonth() + 8);
const upcomingEvents = EVENTS
  .filter(e => { const d = new Date(e.date); return d >= now && d <= eightMonthsLater; })
  .sort((a, b) => new Date(a.date) - new Date(b.date));
if (upcomingEvents.length > 0) {
  html += '<h3>SAP events &mdash; next 8 months</h3><ul>';
  for (const ev of upcomingEvents) {
    const d = new Date(ev.date);
    const ds = d.toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
    html += `<li><b>${escapeHtml(ds)}</b> &mdash; <a href="${escapeHtml(safeUrl(ev.url))}">${escapeHtml(ev.name)}</a> <i>(${escapeHtml(ev.location)})</i>`;
    if (ev.approx) html += ` <i>(date approx.)</i>`;
    html += '</li>';
  }
  html += '</ul>';
}

return [{ json: { html, subject: `SAP News Radar ${dateStr} ${timeStr}` } }];

function escapeHtml(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}
function safeUrl(u) {
  if (!u || typeof u !== 'string') return '#';
  return /^https?:\/\/[^\s<>"']+$/i.test(u.trim()) ? u.trim() : '#';
}

const EVENTS = [
  { name: 'DSAG-Jahreskongress 2026', date: '2026-09-15', location: 'Hamburg', url: 'https://www.dsag.de/jahreskongress', approx: true },
  { name: 'SAP TechEd 2026', date: '2026-10-14', location: 'Berlin / Bangalore (hybrid)', url: 'https://www.sap.com/about/events/sap-teched.html', approx: true },
  { name: 'SAP SuccessConnect 2026', date: '2026-10-27', location: 'Las Vegas', url: 'https://www.sap.com/about/events/successconnect.html', approx: true },
  { name: 'SAPinsider EMEA 2026', date: '2026-11-18', location: 'Kopenhagen', url: 'https://sapinsider.org/events/', approx: true },
  { name: 'ASUG Tech Connect 2027', date: '2027-01-19', location: 'Orlando', url: 'https://www.asug.com/events', approx: true },
  { name: 'SAPinsider Las Vegas 2027', date: '2027-03-09', location: 'Las Vegas', url: 'https://sapinsider.org/events/', approx: true },
  { name: 'SAP Sapphire 2027', date: '2027-05-12', location: 'Orlando', url: 'https://www.sap.com/about/events/sapphire.html', approx: true }
];

const sd = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
const failures = (sd.stats && sd.stats[today] && sd.stats[today].feed_failures) || [];
const now = new Date();
const dateStr = now.toLocaleDateString('en-GB', { timeZone: 'Europe/Berlin' });
const timeStr = now.toLocaleTimeString('en-GB', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });

let html = `<h3>SAP News Radar &ndash; ${escapeHtml(dateStr)} ${escapeHtml(timeStr)}</h3><p><i>No new relevant input. All sources empty or already seen.</i></p>`;

if (failures.length > 0) {
  html += `<p><b>Note:</b> ${failures.length} feed(s) unreachable:</p><ul>`;
  for (const f of failures.slice(0, 10)) {
    html += `<li>${escapeHtml(f.source_id)}</li>`;
  }
  html += '</ul>';
}

const eightMonthsLater = new Date(now);
eightMonthsLater.setMonth(eightMonthsLater.getMonth() + 8);
const upcomingEvents = EVENTS
  .filter(e => { const d = new Date(e.date); return d >= now && d <= eightMonthsLater; })
  .sort((a, b) => new Date(a.date) - new Date(b.date));
if (upcomingEvents.length > 0) {
  html += '<h3>SAP events &mdash; next 8 months</h3><ul>';
  for (const ev of upcomingEvents) {
    const d = new Date(ev.date);
    const ds = d.toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
    html += `<li><b>${escapeHtml(ds)}</b> &mdash; <a href="${escapeHtml(safeUrl(ev.url))}">${escapeHtml(ev.name)}</a> <i>(${escapeHtml(ev.location)})</i>`;
    if (ev.approx) html += ` <i>(date approx.)</i>`;
    html += '</li>';
  }
  html += '</ul>';
}

return [{ json: { html } }];
